using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    List<Course> GetCourses(string? search = null, string? departmentCode = null);
    List<Course> GetFeaturedCourses();
    Course? GetCourseById(int id);
}

public class CatalogService : ICatalogService
{
    private static readonly List<Instructor> Instructors =
    [
        new()
        {
            Name = "Dr. Sarah Chen",
            Title = "Professor of Computer Science",
            Email = "s.chen@university.edu",
            Bio = "Dr. Chen specializes in algorithms and data structures with over 15 years of teaching experience. She has published extensively in computational complexity and mentors undergraduate research projects.",
            OfficeLocation = "Science Building, Room 412"
        },
        new()
        {
            Name = "Dr. Michael Torres",
            Title = "Associate Professor of Mathematics",
            Email = "m.torres@university.edu",
            Bio = "Dr. Torres holds a Ph.D. in Applied Mathematics from MIT. His research focuses on numerical analysis and mathematical modeling, and he has received multiple teaching excellence awards.",
            OfficeLocation = "Math Hall, Room 205"
        },
        new()
        {
            Name = "Prof. Emily Park",
            Title = "Professor of English Literature",
            Email = "e.park@university.edu",
            Bio = "Prof. Park is an award-winning author and literary critic. She specializes in 19th-century American literature and creative writing, bringing published works and real-world experience to the classroom.",
            OfficeLocation = "Humanities Building, Room 310"
        },
        new()
        {
            Name = "Dr. James Wilson",
            Title = "Professor of Physics",
            Email = "j.wilson@university.edu",
            Bio = "Dr. Wilson's research in quantum mechanics and particle physics has been published in leading journals. He brings cutting-edge research directly into his undergraduate lectures.",
            OfficeLocation = "Physics Lab, Room 108"
        },
        new()
        {
            Name = "Dr. Maria Garcia",
            Title = "Associate Professor of History",
            Email = "m.garcia@university.edu",
            Bio = "Dr. Garcia specializes in Latin American history and post-colonial studies. She has conducted fieldwork across Central and South America and integrates primary sources into her teaching.",
            OfficeLocation = "Liberal Arts, Room 220"
        },
        new()
        {
            Name = "Dr. Robert Kim",
            Title = "Assistant Professor of Computer Science",
            Email = "r.kim@university.edu",
            Bio = "Dr. Kim focuses on software engineering and web technologies. Before academia, he spent eight years as a senior engineer at major tech companies, giving him a practical industry perspective.",
            OfficeLocation = "Science Building, Room 415"
        }
    ];

    private static readonly List<Course> AllCourses =
    [
        new()
        {
            Id = 1, Code = "CS101", Title = "Introduction to Computer Science",
            Description = "A foundational course covering programming fundamentals, basic data structures, and algorithmic thinking. Students will learn to write programs in Python and develop problem-solving skills applicable across disciplines.",
            Credits = 4, Schedule = "Mon/Wed/Fri 9:00–9:50 AM",
            DepartmentCode = "CS", DepartmentName = "Computer Science",
            Instructor = Instructors[0], IsFeatured = true
        },
        new()
        {
            Id = 2, Code = "CS201", Title = "Data Structures and Algorithms",
            Description = "An in-depth study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms). Prerequisites: CS101.",
            Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM",
            DepartmentCode = "CS", DepartmentName = "Computer Science",
            Instructor = Instructors[0], IsFeatured = false
        },
        new()
        {
            Id = 3, Code = "CS310", Title = "Web Application Development",
            Description = "Design and build modern web applications using current frameworks and best practices. Covers front-end development, server-side programming, databases, and deployment strategies.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:30 PM",
            DepartmentCode = "CS", DepartmentName = "Computer Science",
            Instructor = Instructors[5], IsFeatured = true
        },
        new()
        {
            Id = 4, Code = "MATH101", Title = "Calculus I",
            Description = "Introduction to differential and integral calculus of single-variable functions. Topics include limits, continuity, derivatives, integrals, and the Fundamental Theorem of Calculus.",
            Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM",
            DepartmentCode = "MATH", DepartmentName = "Mathematics",
            Instructor = Instructors[1], IsFeatured = true
        },
        new()
        {
            Id = 5, Code = "MATH201", Title = "Linear Algebra",
            Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications. Essential for students in mathematics, science, and engineering.",
            Credits = 3, Schedule = "Tue/Thu 1:00–2:30 PM",
            DepartmentCode = "MATH", DepartmentName = "Mathematics",
            Instructor = Instructors[1], IsFeatured = false
        },
        new()
        {
            Id = 6, Code = "ENG110", Title = "Expository Writing",
            Description = "Develop clear, effective writing skills through essay composition, peer review, and revision. Emphasizes critical thinking, argumentation, and proper use of sources.",
            Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM",
            DepartmentCode = "ENG", DepartmentName = "English",
            Instructor = Instructors[2], IsFeatured = false
        },
        new()
        {
            Id = 7, Code = "ENG250", Title = "American Literature Survey",
            Description = "A survey of major American literary works from the colonial period to the present. Explores themes of identity, democracy, and cultural change through novels, poetry, and essays.",
            Credits = 3, Schedule = "Tue/Thu 9:00–10:30 AM",
            DepartmentCode = "ENG", DepartmentName = "English",
            Instructor = Instructors[2], IsFeatured = true
        },
        new()
        {
            Id = 8, Code = "PHYS101", Title = "General Physics I",
            Description = "Introduction to classical mechanics, thermodynamics, and waves. Includes laboratory sessions where students design experiments and analyze data. Co-requisite: MATH101.",
            Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM, Lab: Fri 1:00–3:00 PM",
            DepartmentCode = "PHYS", DepartmentName = "Physics",
            Instructor = Instructors[3], IsFeatured = false
        },
        new()
        {
            Id = 9, Code = "PHYS220", Title = "Modern Physics",
            Description = "Introduction to 20th-century physics: special relativity, quantum mechanics, atomic and nuclear physics. Prerequisites: PHYS101, MATH201.",
            Credits = 3, Schedule = "Mon/Wed 3:00–4:30 PM",
            DepartmentCode = "PHYS", DepartmentName = "Physics",
            Instructor = Instructors[3], IsFeatured = true
        },
        new()
        {
            Id = 10, Code = "HIST101", Title = "World History to 1500",
            Description = "Survey of major civilizations, cultural exchanges, and historical developments from prehistory through the late medieval period. Emphasizes primary source analysis and historical thinking.",
            Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM",
            DepartmentCode = "HIST", DepartmentName = "History",
            Instructor = Instructors[4], IsFeatured = false
        },
        new()
        {
            Id = 11, Code = "HIST240", Title = "Modern Latin America",
            Description = "Examines the political, social, and cultural history of Latin America from independence to the present. Topics include revolution, migration, globalization, and identity.",
            Credits = 3, Schedule = "Tue/Thu 2:30–4:00 PM",
            DepartmentCode = "HIST", DepartmentName = "History",
            Instructor = Instructors[4], IsFeatured = false
        },
        new()
        {
            Id = 12, Code = "CS450", Title = "Machine Learning",
            Description = "Introduction to machine learning concepts and techniques including supervised and unsupervised learning, neural networks, and model evaluation. Prerequisites: CS201, MATH201.",
            Credits = 3, Schedule = "Tue/Thu 3:00–4:30 PM",
            DepartmentCode = "CS", DepartmentName = "Computer Science",
            Instructor = Instructors[5], IsFeatured = true
        }
    ];

    public List<Department> GetDepartments()
    {
        return AllCourses
            .GroupBy(c => new { c.DepartmentCode, c.DepartmentName })
            .Select(g => new Department
            {
                Code = g.Key.DepartmentCode,
                Name = g.Key.DepartmentName,
                CourseCount = g.Count()
            })
            .OrderBy(d => d.Name)
            .ToList();
    }

    public List<Course> GetCourses(string? search = null, string? departmentCode = null)
    {
        var query = AllCourses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentCode))
        {
            query = query.Where(c => c.DepartmentCode.Equals(departmentCode, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.Code).ToList();
    }

    public List<Course> GetFeaturedCourses()
    {
        return AllCourses.Where(c => c.IsFeatured).OrderBy(c => c.Code).ToList();
    }

    public Course? GetCourseById(int id)
    {
        return AllCourses.FirstOrDefault(c => c.Id == id);
    }
}

@using UniversityCourseCatalog.Models

<div class="card h-100">
    <div class="card-body">
        <span class="badge bg-secondary mb-2">@Course.DepartmentName</span>
        @if (Course.IsFeatured)
        {
            <span class="badge bg-warning text-dark mb-2">⭐ Featured</span>
        }
        <h5 class="card-title">
