@page "/catalog"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Components.Shared
@inject ICatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="/catalog" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search"
               value="@Search" placeholder="Search by title, code, or instructor…" />
    </div>
    <div class="col-md-4">
        <label for="department" class="form-label">Department</label>
        <select class="form-select" id="department" name="department">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Code" selected="@(dept.Code == Department)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @courses.Count course(s)</p>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var course in courses)
        {
            <div class="col">
                <CourseCard Course="course" />
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery(Name = "department")]
    public string? Department { get; set; }

    private List<Course> courses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, Department);
    }
}

