@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Components.Shared
@inject ICatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4">University Course Catalog</h1>
    <p class="lead text-muted">Browse departments, explore courses, and submit enrollment requests.</p>
    <a href="/catalog" class="btn btn-primary btn-lg mt-2">Browse All Courses</a>
</div>

<section class="mb-5">
    <h2>Featured Courses</h2>
    <hr />
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var course in featuredCourses)
        {
            <div class="col">
                <CourseCard Course="course" />
            </div>
        }
    </div>
</section>

<section>
    <h2>Departments</h2>
    <hr />
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var dept in departments)
        {
            <div class="col">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@dept.Name</h5>
                        <p class="card-text text-muted">@dept.CourseCount course(s) available</p>
                        <a href="/catalog?department=@dept.Code" class="btn btn-outline-primary btn-sm">
                            View Courses
                        </a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

@code {
    private List<Course> featuredCourses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }
}

toolArgs.file_text:
@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p class="text-muted">Fill out the form below to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>
            Thank you, <strong>@Model.FullName</strong>. Your enrollment request for
            <strong>@(selectedCourse?.Code) — @(selectedCourse?.Title)</strong> has been received.
            You will be notified by email once your request is processed.
        </p>
        <a href="/catalog" class="btn btn-outline-primary">Back to Catalog</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <EditForm Model="Model" FormName="enrollment" method="post" OnValidSubmit="HandleSubmit">
                <DataAnnotationsValidator />
                <AntiforgeryToken />
                <ValidationSummary class="text-danger mb-3" />

                <div class="mb-3">
                    <label for="fullName" class="form-label">Full Name</label>
                    <InputText id="fullName" class="form-control" @bind-Value="Model.FullName" />
                    <ValidationMessage For="() => Model.FullName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in allCourses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="comments" class="form-label">Comments (optional)</label>
                    <InputTextArea id="comments" class="form-control" rows="3" @bind-Value="Model.Comments" />
                    <ValidationMessage For="() => Model.Comments" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-success">Submit Request</button>
                <a href="/catalog" class="btn btn-outline-secondary ms-2">Cancel</a>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> allCourses = [];
    private Course? selectedCourse;
    private bool submitted;

    protected override void OnInitialized()
    {
        allCourses = Catalog.GetCourses();

        if (!submitted && CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        selectedCourse = Catalog.GetCourseById(Model.CourseId);
        submitted = true;
    }
}

